#!/usr/bin/env bash
# qualify-disqualify-an-opportunit.sh — Qualify / disqualify an opportunity with MEDDPICC（用 MEDDPICC 资格审查一个机会） SOP walkthrough for B2B 大客户销售.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="B2B 大客户销售"
WORKFLOW="Qualify / disqualify an opportunity with MEDDPICC（用 MEDDPICC 资格审查一个机会）"

usage() {
  cat <<EOF
qualify-disqualify-an-opportunit.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./qualify-disqualify-an-opportunit.sh             # interactive
  ./qualify-disqualify-an-opportunit.sh --dry-run
  ./qualify-disqualify-an-opportunit.sh --json
  ./qualify-disqualify-an-opportunit.sh --explain
  ./qualify-disqualify-an-opportunit.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Qualify / disqualify an opportunity with MEDDPICC（用 MEDDPICC 资格审查一个机会）" 工作流。

一句话: Decide *which deals are real* — score an opportunity against MEDDPICC, and either commit resources or **disqualify early** ("no deal beats a bad deal"). The discipline that keeps reps off doomed deals; its dark twin is **box-checking theater**. (evidence: [T03-S005, T03-S036])

入门 SOP 共 5 步, 失败模式自检 4 项。

相关心智模型:
  • 问 ⇄ 教 ⇄ 筛:三派第一性张力,资深人按层混用: 复杂销售的方法论分三派——诊断式提问(SPIN/Gap:「客户有答案,问到痛点不可否认为止」)⇄ 挑战式教学(Challenger:「客户对自己问题的认知是错的,用商业洞见 reframe」)⇄ 资格
  • 头号对手是「不决策」,不是竞品: 预测内丢单的最大去向不是输给对手,而是客户「什么都不做」——维持现状;且一旦购买意向形成,买方更怕「搞砸」(FOMU)而非「错过」(FOMO),所以晚期停滞要按「犹豫」处理(去风险),不是按「异议」处

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**Identify Pain + Metrics** — confirm a real, quantified business problem (M = the buyer's ROI number, not your feature). (evidence: [T03-S005])"
  "**Find the Economic Buyer** — name the one person who can say yes when everyone else says no (P&L authority + discretionary budget). (evidence: [T03-S007])"
  "**Map Decision Criteria + Decision Process** — the (often unstated) rules and the steps/people by which they'll decide (note: Decision Process = technical validation + business approval, two parts). (evidence: [T03-S008])"
  "**Secure + test a Champion** — someone with power, influence, and *vested interest* who sells for you when you're not in the room. (evidence: [T03-S006])"
  "**Map Paper Process + Competition** — the procurement/legal/security path to signature + who/what you're really competing against (often the status quo). (evidence: [T03-S005, T03-S032])"
)
declare -a FAILURE_MODES=(
  "**Box-checking theater — filling MEDDPICC CRM fields without real qualification**: a fully-populated scorecard is *not* a qualified deal. Avoid: managers inspect *quality* (can you name + prove the EB?), enforce exit criteria, and coach the thinking — not the field-completion. (evidence: [T03-S005])"
  "**Mistaking a Coach for a Champion**: the friendly contact who gives intel but has no power can't move the deal. Avoid: test the champion — make them do something for you. (evidence: [T03-S006])"
  "**Never confirming the Economic Buyer**: you sell to the champion's ceiling and the deal can't get budget. Avoid: if you can't name the EB, the deal is unqualified — treat that as a red flag, not a detail. (evidence: [T03-S007])"
  "**Treating MEDDPICC as a full sales method**: it's *qualification only* — it tells you what to know, not how to run discovery or articulate value. Avoid: pair it with SPIN/Gap (discover) + Command of the Message (value). (evidence: [T03-S005])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "qualify-disqualify-an-opportunit-walkthrough"
fi
